class NestedIterator:
    def __init__(self, nestedList):
        self.res, self.cur = [], 0
        def flatten(lst):
            for x in lst:
                if x.isInteger(): self.res.append(x.getInteger())
                else: flatten(x.getList())
        flatten(nestedList)
    def next(self): self.cur += 1; return self.res[self.cur-1]
    def hasNext(self): return self.cur < len(self.res)

